def coverage_report(cases: list[dict]) -> dict:
    from collections import defaultdict
    by_dim: dict[str, list] = defaultdict(list)
    for c in cases:
        by_dim[c["dimension"]].append(c)

    report = {}
    for dim, group in by_dim.items():
        total = len(group)
        passed = sum(1 for c in group if c.get("last_result") == "pass")
        report[dim] = {
            "total": total,
            "passed": passed,
            "pass_rate": round(passed / total, 3) if total else None,
            "sub_types": list({c["sub_type"] for c in group}),
        }
    return report
